// RSA-OAEP SHA-256 encryption of KSeF token
// Format: authToken|timestampMs encrypted with KSeF public certificate
const crypto = require('crypto');
const config = $('⚙️ Config').first().json;

const challengeData = $input.first().json;
const challenge = challengeData.challenge;
const timestampMs = challengeData.timestampMs;

// Get public key(s) from Get Public Key node
const keyItems = $('Get Public Key').all();
let publicKeys;
if (Array.isArray(keyItems[0].json)) {
  publicKeys = keyItems[0].json;
} else if (keyItems.length > 1) {
  publicKeys = keyItems.map(i => i.json);
} else {
  publicKeys = [keyItems[0].json];
}

// Find the key for token encryption
const encKey = publicKeys.find(k => 
  (k.usage && k.usage.includes('KsefTokenEncryption')) ||
  (k.usageTypes && k.usageTypes.includes('KsefTokenEncryption'))
) || publicKeys[0];

// Prepare plaintext: authToken|timestampMs
const plaintext = `${config.authToken}|${timestampMs}`;

// Convert certificate to PEM format with proper 64-char line breaks
const certBase64 = typeof encKey === 'string' ? encKey : (encKey.certificate || encKey.publicKey);
let certPem;
if (certBase64.includes('-----BEGIN')) {
  certPem = certBase64;
} else {
  const formatted = certBase64.match(/.{1,64}/g).join('\n');
  certPem = `-----BEGIN CERTIFICATE-----\n${formatted}\n-----END CERTIFICATE-----`;
}

// Encrypt with RSA-OAEP SHA-256 + MGF1
const encryptedBuffer = crypto.publicEncrypt(
  {
    key: certPem,
    padding: crypto.constants.RSA_PKCS1_OAEP_PADDING,
    oaepHash: 'sha256'
  },
  Buffer.from(plaintext)
);
const encryptedToken = encryptedBuffer.toString('base64');

return [{
  json: {
    challenge: challenge,
    contextIdentifier: {
      type: 'Nip',
      value: config.nip
    },
    encryptedToken: encryptedToken
  }
}];

// Collect all invoices from paginated results
const pages = $input.all();
const allInvoices = [];

for (const page of pages) {
  if (page.json.invoices && Array.isArray(page.json.invoices)) {
    const type = page.json.type;

    allInvoices.push(
      ...page.json.invoices.map(inv => ({
        ...inv,
        type,
      }))
    );
  }
}

if (allInvoices.length === 0) {
  return [{ json: { _noInvoices: true, message: 'No invoices found in the specified date range', count: 0 } }];
}

console.log(`Found ${allInvoices.length} invoices`);
return allInvoices.map(inv => ({ json: inv }));

// ─── strip ns prefix recursively ───────────────────────────────────────────
function stripNs(obj) {
  if (Array.isArray(obj)) return obj.map(stripNs);
  if (obj !== null && typeof obj === 'object') {
    return Object.fromEntries(
      Object.entries(obj).map(([k, v]) => [k.replace(/^[^:]+:/, ''), stripNs(v)])
    );
  }
  return obj;
}

const raw = $input.first().json;
const input = stripNs(raw);

// ─── root: obsługa z Faktura lub bez ───────────────────────────────────────
const f = input.Faktura ?? Object.values(input)[0];
const fa = f.Fa;

// ─── helpers ───────────────────────────────────────────────────────────────
const safe = (val, fallback = '—') =>
  (val !== undefined && val !== null && val !== '') ? val : fallback;
const safeGet = (obj, ...keys) =>
  keys.reduce((o, k) => (o && o[k] !== undefined ? o[k] : undefined), obj);

// ─── wiersze: FaWiersz (VAT) lub ZamowienieWiersz (ZAL) ──────────────────
const rodzaj = safe(fa.RodzajFaktury, 'VAT');

let wiersze = [];
if (fa.FaWiersz) {
  const raw = fa.FaWiersz;
  wiersze = Array.isArray(raw) ? raw : [raw];
} else if (fa.Zamowienie) {
  const zam = fa.Zamowienie;
  const rawZ = zam.ZamowienieWiersz;
  const arr = Array.isArray(rawZ) ? rawZ : (rawZ ? [rawZ] : []);
  // normalizacja do wspólnego formatu
  wiersze = arr.map(w => ({
    NrWierszaFa: w.NrWierszaZam,
    P_7:  w.P_7Z,
    P_8A: w.P_8AZ,
    P_8B: w.P_8BZ,
    P_9A: w.P_9AZ,
    P_11: w.P_11NettoZ,
    P_11Vat: w.P_11VatZ,
    P_12: w.P_12Z,
  }));
}

// ─── kwota / cena jedn. ────────────────────────────────────────────────────
const kwotaWiersza = (w) => safe(w.P_11 ?? w.P_11A);
const cenaJedn     = (w) => safe(w.P_9A ?? w.P_9B);

// ─── okres faktury ─────────────────────────────────────────────────────────
const okresOd = safeGet(fa, 'OkresFa', 'P_6_Od');
const okresDo = safeGet(fa, 'OkresFa', 'P_6_Do');
const okresHtml = (okresOd && okresDo)
  ? `<div><label>Okres faktury</label><span>${okresOd} – ${okresDo}</span></div>`
  : '';

// ─── daty płatności ────────────────────────────────────────────────────────
const dataZaplaty =
  safeGet(fa, 'Platnosc', 'DataZaplaty') ??
  safeGet(fa, 'Platnosc', 'TerminPlatnosci', 'Termin') ?? '—';

// ─── do zapłaty ────────────────────────────────────────────────────────────
const doZaplaty = safe(fa.P_15 ?? safeGet(fa, 'Rozliczenie', 'DoZaplaty'));

// ─── KRS / REGON ───────────────────────────────────────────────────────────
const krs  = safeGet(f, 'Stopka', 'Rejestry', 'KRS');
const regon = safeGet(f, 'Stopka', 'Rejestry', 'REGON');
const krsHtml  = krs   ? `KRS: ${krs} &nbsp;|&nbsp; ` : '';
const regonHtml = regon ? `REGON: ${regon}` : '';

// ─── rachunek bankowy ──────────────────────────────────────────────────────
const nrRB = safeGet(fa, 'Platnosc', 'RachunekBankowy', 'NrRB');
const nrRBHtml = nrRB
  ? `<div><div class="fl">Rachunek bankowy</div>${nrRB}</div>` : '';

// ─── stopka ────────────────────────────────────────────────────────────────
const stopkaFaktury = safeGet(f, 'Stopka', 'Informacje', 'StopkaFaktury') ?? '';

// ─── rozliczenie ───────────────────────────────────────────────────────────
const rozliczenie = fa.Rozliczenie;
let rozliczenieHtml = '';
if (rozliczenie) {
  const obciazenia = Array.isArray(rozliczenie.Obciazenia)
    ? rozliczenie.Obciazenia
    : (rozliczenie.Obciazenia ? [rozliczenie.Obciazenia] : []);
  if (obciazenia.length > 0) {
    const oRows = obciazenia.map(o =>
      `<tr><td class="muted">${safe(o.Powod)}</td><td style="text-align:right">${safe(o.Kwota)} PLN</td></tr>`
    ).join('');
    rozliczenieHtml = `
      <div style="display:flex;justify-content:flex-end;margin-bottom:28px;">
        <table class="tot-t">
          <tr><td colspan="2" style="font-size:11px;text-transform:uppercase;letter-spacing:.07em;color:#01696f;padding-bottom:8px;font-weight:600;">Rozliczenie</td></tr>
          ${oRows}
          <tr class="tot-row">
            <td>Do zapłaty (z rozliczeniem)</td>
            <td>${safe(rozliczenie.DoZaplaty)} PLN</td>
          </tr>
        </table>
      </div>`;
  }
}

// ─── wiersze tabeli ────────────────────────────────────────────────────────
const rows = wiersze.map((w, i) => `
  <tr>
    <td>${i + 1}</td>
    <td class="desc">
      ${safe(w.P_7)}
      <div class="item-id">Nr wiersza: ${safe(w.NrWierszaFa)}</div>
    </td>
    <td style="text-align:right">${safe(w.P_8B)}</td>
    <td style="text-align:right">${cenaJedn(w)}</td>
    <td style="text-align:right">${safe(w.P_12)}%</td>
    <td style="text-align:right"><strong>${kwotaWiersza(w)} PLN</strong></td>
  </tr>
`).join('');

// ─── badge ─────────────────────────────────────────────────────────────────
const zaplacono = safeGet(fa, 'Platnosc', 'Zaplacono');
const badgeHtml = zaplacono === '1'
  ? `<div class="badge">&#10003; Zapłacono</div>`
  : `<div class="badge badge-pending">Termin: ${dataZaplaty}</div>`;

// ─── HTML ──────────────────────────────────────────────────────────────────
const html = `<!DOCTYPE html>
<html lang="pl">
<head>
<meta charset="UTF-8">
<title>Faktura ${safe(fa.P_2)}</title>
<style>
  :root { --primary: #01696f; --text: #28251d; --muted: #7a7974; --divider: #dcd9d5; --bg: #f7f6f2; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, 'Helvetica Neue', sans-serif; font-size: 14px; line-height: 1.6; color: var(--text); background: var(--bg); padding: 40px 20px; }
  .wrap { max-width: 860px; margin: 0 auto; background: #fff; border-radius: 10px; padding: 48px 56px; box-shadow: 0 4px 12px rgba(40,37,29,.08); }
  .hdr { display: flex; justify-content: space-between; align-items: flex-start; border-bottom: 1px solid var(--divider); padding-bottom: 28px; margin-bottom: 32px; }
  .title { font-size: 26px; font-weight: 700; }
  .nr { font-size: 13px; color: var(--muted); margin-top: 4px; }
  .rodzaj { font-size: 12px; color: var(--primary); font-weight: 600; margin-top: 2px; text-transform: uppercase; letter-spacing: .06em; }
  .badge { background: #d4dfcc; color: #437a22; padding: 6px 14px; border-radius: 999px; font-size: 13px; font-weight: 600; }
  .badge-pending { background: #e9e0c6; color: #8a5b00; }
  .parties { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; margin-bottom: 28px; }
  .party h3 { font-size: 11px; text-transform: uppercase; letter-spacing: .08em; color: var(--muted); margin-bottom: 8px; }
  .pname { font-size: 15px; font-weight: 600; margin-bottom: 4px; }
  .pdet { font-size: 13px; color: var(--muted); line-height: 1.7; }
  .meta { display: grid; grid-template-columns: repeat(4,1fr); gap: 12px; background: var(--bg); border-radius: 8px; padding: 18px 20px; margin-bottom: 32px; }
  .meta label { display: block; font-size: 10px; text-transform: uppercase; letter-spacing: .07em; color: var(--muted); margin-bottom: 3px; }
  .meta span { font-size: 14px; font-weight: 500; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 24px; }
  thead tr { border-bottom: 2px solid var(--primary); }
  th { padding: 9px 10px; text-align: left; font-size: 11px; text-transform: uppercase; letter-spacing: .07em; color: var(--primary); }
  td { padding: 12px 10px; font-size: 13px; vertical-align: top; border-bottom: 1px solid var(--divider); }
  tbody tr:last-child td { border-bottom: none; }
  .desc { max-width: 320px; word-break: break-word; }
  .item-id { font-size: 11px; color: var(--muted); margin-top: 2px; }
  .muted { color: var(--muted); }
  .tot-t { width: 300px; }
  .tot-t td { padding: 5px 0; font-size: 13px; border: none; }
  .tot-t td:last-child { text-align: right; font-weight: 500; }
  .tot-row td { padding-top: 10px; border-top: 2px solid var(--primary) !important; font-size: 16px; font-weight: 700; color: var(--primary); }
  .footer { border-top: 1px solid var(--divider); padding-top: 20px; font-size: 12px; color: var(--muted); line-height: 1.7; display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
  .fl { font-weight: 600; text-transform: uppercase; font-size: 10px; letter-spacing: .06em; margin-bottom: 3px; }
  @media print { body { background: #fff; padding: 0; } .wrap { box-shadow: none; } }
</style>
</head>
<body>
<div class="wrap">

  <div class="hdr">
    <div>
      <div class="title">Faktura VAT</div>
      <div class="nr">Nr ${safe(fa.P_2)}</div>
      <div class="rodzaj">${rodzaj}</div>
    </div>
    ${badgeHtml}
  </div>

  <div class="parties">
    <div class="party">
      <h3>Sprzedawca</h3>
      <div class="pname">${safe(safeGet(f, 'Podmiot1', 'DaneIdentyfikacyjne', 'Nazwa'))}</div>
      <div class="pdet">
        NIP: ${safe(safeGet(f, 'Podmiot1', 'DaneIdentyfikacyjne', 'NIP'))}<br>
        ${safe(safeGet(f, 'Podmiot1', 'Adres', 'AdresL1'))}<br>
        ${safe(safeGet(f, 'Podmiot1', 'Adres', 'AdresL2'), '')}
      </div>
    </div>
    <div class="party">
      <h3>Nabywca</h3>
      <div class="pname">${safe(safeGet(f, 'Podmiot2', 'DaneIdentyfikacyjne', 'Nazwa'))}</div>
      <div class="pdet">
        NIP: ${safe(safeGet(f, 'Podmiot2', 'DaneIdentyfikacyjne', 'NIP'))}<br>
        ${safe(safeGet(f, 'Podmiot2', 'Adres', 'AdresL1'))}<br>
        ${safe(safeGet(f, 'Podmiot2', 'Adres', 'AdresL2'), '')}
      </div>
    </div>
  </div>

  <div class="meta">
    <div><label>Data wystawienia</label><span>${safe(fa.P_1)}</span></div>
    ${okresHtml}
    <div><label>Termin płatności</label><span>${dataZaplaty}</span></div>
    <div><label>Waluta</label><span>${safe(fa.KodWaluty)}</span></div>
  </div>

  <table>
    <thead>
      <tr>
        <th>Lp.</th>
        <th>Opis usługi</th>
        <th style="text-align:right">Ilość</th>
        <th style="text-align:right">Cena jedn.</th>
        <th style="text-align:right">VAT</th>
        <th style="text-align:right">Kwota</th>
      </tr>
    </thead>
    <tbody>${rows}</tbody>
  </table>

  <div style="display:flex;justify-content:flex-end;margin-bottom:28px;">
    <table class="tot-t">
      <tr><td class="muted">Netto</td><td>${safe(fa.P_13_1)} PLN</td></tr>
      <tr><td class="muted">VAT</td><td>${safe(fa.P_14_1)} PLN</td></tr>
      <tr class="tot-row"><td>Do zapłaty</td><td>${doZaplaty} PLN</td></tr>
    </table>
  </div>

  ${rozliczenieHtml}

  <div class="footer">
    <div>
      <div class="fl">Dane rejestrowe</div>
      ${krsHtml}${regonHtml}
    </div>
    ${stopkaFaktury ? `<div><div class="fl">Informacje</div>${stopkaFaktury}</div>` : ''}
    ${nrRBHtml}
  </div>

</div>
</body>
</html>`;

return [{  "invoiceHTML": html  }];
